const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// SportWarren Database Schema\n// Core MVP: Match Verification → XP → Engagement\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================================================\n// USER & AUTHENTICATION\n// ============================================================================\n\nmodel User {\n  id            String  @id @default(cuid())\n  email         String? @unique\n  walletAddress String  @unique @map(\"wallet_address\")\n  chain         String // 'algorand', 'avalanche', or 'lens'\n\n  // Profile\n  name     String?\n  avatar   String?\n  position String? // Preferred position\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  playerProfile      PlayerProfile?\n  squads             SquadMember[]\n  platformIdentities PlatformIdentity[]\n  telegramLinkCodes  TelegramLinkCode[]\n  matchesSubmitted   Match[]              @relation(\"MatchSubmitter\")\n  verifications      MatchVerification[]\n  aiMemory           AiMemory?\n  squadContexts      SquadPlayerContext[]\n  squadMedia         SquadMedia[]\n\n  // Availability (Multi-squad support)\n  availabilities SquadAvailability[]\n  matchRsvps     MatchRsvp[]\n\n  @@map(\"users\")\n}\n\n// ============================================================================\n// PLAYER PROFILE (XP & ATTRIBUTES)\n// ============================================================================\n\nmodel PlayerProfile {\n  id     String @id @default(cuid())\n  userId String @unique @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Level & XP\n  level    Int @default(1)\n  totalXP  Int @default(0) @map(\"total_xp\")\n  seasonXP Int @default(0) @map(\"season_xp\")\n\n  // Career Stats\n  totalMatches Int @default(0) @map(\"total_matches\")\n  totalGoals   Int @default(0) @map(\"total_goals\")\n  totalAssists Int @default(0) @map(\"total_assists\")\n\n  // Weekly Schedule (0=Sunday, 1=Monday, etc.)\n  matchDayPreference Int @default(0) @map(\"match_day_preference\")\n\n  // Physical Condition (0-100)\n  sharpness Int @default(50) @map(\"sharpness\")\n\n  // Reputation\n  reputationScore Int @default(100) @map(\"reputation_score\")\n\n  // Scout (Peer Rating)\n  scoutXP   Int    @default(0) @map(\"scout_xp\")\n  scoutTier String @default(\"rookie\") @map(\"scout_tier\") // rookie, trusted, elite\n  hypeTags  Json?  @map(\"hype_tags\") // { \"Clutch\": 5, \"Engine\": 3 }\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  attributes        PlayerAttribute[]\n  matchStats        PlayerMatchStats[]\n  formHistory       FormEntry[]\n  activities        PhysicalActivity[]\n  ratingsGiven      PeerRating[]       @relation(\"RatingGiven\")\n  ratingsReceived   PeerRating[]       @relation(\"RatingReceived\")\n  motmVotesGiven    MotmVote[]         @relation(\"MotmVoteGiven\")\n  motmVotesReceived MotmVote[]         @relation(\"MotmVoteReceived\")\n  sessionsAttended  SessionAttendee[]\n  twin              PlayerTwin?\n\n  @@map(\"player_profiles\")\n}\n\nmodel PhysicalActivity {\n  id        String        @id @default(cuid())\n  profileId String        @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  type      String // 'run', 'gym', 'hiit', 'field_training'\n  duration  Int // minutes\n  intensity String // 'low', 'medium', 'high'\n  distance  Float? // km, if applicable\n  calories  Int?\n\n  // Provider info\n  source     String  @default(\"manual\") // 'manual', 'strava', 'apple_health'\n  externalId String? @map(\"external_id\")\n\n  // Impact\n  xpGained      Int @default(0) @map(\"xp_gained\")\n  sharpnessGain Int @default(0) @map(\"sharpness_gain\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"physical_activities\")\n}\n\nmodel PlayerAttribute {\n  id        String        @id @default(cuid())\n  profileId String        @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  // Attribute type: pace, shooting, passing, dribbling, defending, physical\n  attribute String\n  rating    Int    @default(50) // 0-99 FIFA style\n  xp        Int    @default(0)\n  xpToNext  Int    @default(100) @map(\"xp_to_next\")\n  maxRating Int    @default(99) @map(\"max_rating\")\n\n  // History (last 5 match ratings for this attribute)\n  history Int[]\n\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@unique([profileId, attribute])\n  @@map(\"player_attributes\")\n}\n\nmodel FormEntry {\n  id        String        @id @default(cuid())\n  profileId String        @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  matchId   String @map(\"match_id\")\n  rating    Float // Match rating 1-10\n  formValue Int    @map(\"form_value\") // Calculated -5 to +5\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"form_entries\")\n}\n\n// ============================================================================\n// SQUADS\n// ============================================================================\n\nmodel Squad {\n  id        String  @id @default(cuid())\n  name      String\n  shortName String  @map(\"short_name\")\n  logo      String?\n\n  // Squad details\n  founded    DateTime @default(now())\n  homeGround String?  @map(\"home_ground\")\n\n  // Weekly Schedule (0=Sunday, 1=Monday, etc.)\n  preferredMatchDay Int @default(0) @map(\"preferred_match_day\")\n\n  // Treasury (simplified for MVP)\n  treasuryBalance Int @default(0) @map(\"treasury_balance\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Digital Twin & Seasonality\n  level                Int      @default(1)\n  xp                   Int      @default(0)\n  digitalAttributes    Json?    @map(\"digital_attributes\") // { attack, defense, midfield, teamwork, prestige }\n  seasonPoints         Int      @default(0) @map(\"season_points\")\n  squadEnergy          Int      @default(100) @map(\"squad_energy\") // 0-100, affected by IRL commitment\n  lastSeasonSync       DateTime @default(now()) @map(\"last_season_sync\")\n  isDigitalTwinActive  Boolean  @default(true) @map(\"is_digital_twin_active\")\n  digitalTwin3dEnabled Boolean  @default(false) @map(\"digital_twin_3d_enabled\")\n  digitalTwin3dTier    String?  @map(\"digital_twin_3d_tier\") // premium, streak_reward, partner, internal\n\n  // Relations\n  members            SquadMember[]\n  groups             SquadGroup[]\n  squadContexts      SquadPlayerContext[]\n  matchesHome        Match[]              @relation(\"MatchHomeSquad\")\n  matchesAway        Match[]              @relation(\"MatchAwaySquad\")\n  tactics            SquadTactics?\n  treasury           SquadTreasury?\n  transferOffersFrom TransferOffer[]      @relation(\"TransferFromSquad\")\n  transferOffersTo   TransferOffer[]      @relation(\"TransferToSquad\")\n  challengesFrom     MatchChallenge[]     @relation(\"ChallengeFromSquad\")\n  challengesTo       MatchChallenge[]     @relation(\"ChallengeToSquad\")\n  sessions           Session[]\n\n  // Availability & Scheduling (Multi-squad support)\n  availabilities SquadAvailability[]\n  schedule       SquadSchedule?\n\n  // Media (private/squad/public)\n  media   SquadMedia[]\n  secrets SquadSecret[]\n\n  // On-chain Governance\n  governorAddress String? @map(\"governor_address\")\n  tokenAddress    String? @map(\"token_address\")\n\n  @@map(\"squads\")\n}\n\nmodel SquadMember {\n  id      String @id @default(cuid())\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Role\n  role     String   @default(\"player\") // captain, vice_captain, player\n  joinedAt DateTime @default(now()) @map(\"joined_at\")\n\n  // Temporal membership tracking for multi-squad support\n  validFrom DateTime? @map(\"valid_from\") // When membership started\n  validTo   DateTime? @map(\"valid_to\") // When membership ended (null = active)\n  status    String    @default(\"active\") // active, inactive, paused\n\n  // Reverse relation for match submissions\n  submittedMatches Match[] @relation(\"MatchSubmitterMembership\")\n\n  @@unique([squadId, userId])\n  @@map(\"squad_members\")\n}\n\n// ============================================================================\n// SQUAD PLAYER CONTEXT (Per-Squad Stats & Role Progression)\n// ============================================================================\n\nmodel SquadPlayerContext {\n  id     String @id @default(cuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  // Position in THIS squad (can differ from global preference)\n  position String? // GK, DF, MF, ST, WG\n\n  // Role in this squad\n  role String @default(\"player\") // captain, vice_captain, player\n\n  // Per-squad XP (separate from global career XP)\n  squadXP Int @default(0) @map(\"squad_xp\")\n\n  // Contextual stats (varies by squad)\n  sharpness Int    @default(50) // 0-100, contextual fitness\n  form      String @default(\"neutral\") // hot, neutral, cold\n\n  // Per-squad match stats\n  matchesPlayed Int @default(0) @map(\"matches_played\")\n  goals         Int @default(0)\n  assists       Int @default(0)\n\n  // Timestamps\n  joinedAt  DateTime @default(now()) @map(\"joined_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@unique([userId, squadId])\n  @@map(\"squad_player_context\")\n}\n\nmodel SquadGroup {\n  id             String    @id @default(cuid())\n  squadId        String    @map(\"squad_id\")\n  squad          Squad     @relation(fields: [squadId], references: [id], onDelete: Cascade)\n  platform       String\n  chatId         String?   @map(\"chat_id\")\n  platformUserId String?   @map(\"platform_user_id\")\n  username       String?\n  linkToken      String?   @unique @map(\"link_token\")\n  linkedAt       DateTime? @map(\"linked_at\")\n\n  @@unique([platform, chatId])\n  @@map(\"squad_groups\")\n}\n\n// ============================================================================\n// PLATFORM IDENTITY (User-Scoped Telegram/Discord Identity)\n// ============================================================================\n\nmodel PlatformIdentity {\n  id     String @id @default(cuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  platform       String // telegram, discord\n  platformUserId String  @map(\"platform_user_id\") // Telegram user ID (stable)\n  chatId         String? @map(\"chat_id\") // Last group chat context\n  username       String?\n  firstName      String? @map(\"first_name\") // Telegram first name\n  photoUrl       String? @map(\"photo_url\") // Telegram profile photo URL\n\n  // Session fields (moved from PlatformConnection)\n  miniAppToken          String?   @unique @map(\"mini_app_token\")\n  miniAppTokenExpiresAt DateTime? @map(\"mini_app_token_expires_at\")\n  activeSquadId         String?   @map(\"active_squad_id\") // Last-used squad context\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@unique([platform, platformUserId])\n  @@map(\"platform_identities\")\n}\n\n// Telegram link codes for self-service linking\nmodel TelegramLinkCode {\n  id     String @id @default(cuid())\n  code   String @unique\n  chatId String @map(\"chat_id\") // Telegram chat ID\n  userId String @map(\"user_id\") // User to link to\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  expiresAt DateTime  @map(\"expires_at\")\n  usedAt    DateTime? @map(\"used_at\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@index([chatId])\n  @@index([userId])\n  @@map(\"telegram_link_codes\")\n}\n\n// ============================================================================\n// SQUAD TACTICS\n// ============================================================================\n\nmodel SquadTactics {\n  id      String @id @default(cuid())\n  squadId String @unique @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  // Formation (4-4-2, 4-3-3, etc.)\n  formation String @default(\"4-4-2\")\n\n  // Play style\n  playStyle String @default(\"balanced\") @map(\"play_style\")\n\n  // Team instructions (JSON)\n  instructions Json? // { width, tempo, passing, pressing, defensiveLine }\n\n  // Set pieces (JSON)\n  setPieces Json? @map(\"set_pieces\") // { corners, freeKicks, penalties }\n\n  // Starting lineup (array of player IDs aligned to formation slots)\n  lineup Json? @map(\"lineup\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"squad_tactics\")\n}\n\n// DAO GOVERNANCE (PROPOSALS & VOTING) - Moved to Avalanche Smart Contracts\n\n// ============================================================================\n// TREASURY & TRANSACTIONS\n// ============================================================================\n\nmodel SquadTreasury {\n  id      String @id @default(cuid())\n  squadId String @unique @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  // Balance in smallest unit (e.g., microALGO)\n  balance          Int     @default(0)\n  yellowSessionId  String? @map(\"yellow_session_id\")\n  tonWalletAddress String? @map(\"ton_wallet_address\")\n\n  // Budgets (JSON)\n  budgets Json? // { wages, transfers, facilities }\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  transactions TreasuryTransaction[]\n\n  @@map(\"squad_treasury\")\n}\n\nmodel TreasuryTransaction {\n  id         String        @id @default(cuid())\n  treasuryId String        @map(\"treasury_id\")\n  treasury   SquadTreasury @relation(fields: [treasuryId], references: [id], onDelete: Cascade)\n\n  // Transaction type\n  type String // income, expense\n\n  // Category\n  category String // transfer_in, transfer_out, match_fee, tournament_prize, facility, wage\n\n  // Amount\n  amount Int\n\n  // Description\n  description String?\n\n  // Verification (blockchain tx hash)\n  txHash   String? @map(\"tx_hash\")\n  verified Boolean @default(false)\n  metadata Json?\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"treasury_transactions\")\n}\n\n// ============================================================================\n// SOCIAL: SQUAD MEDIA (PRIVATE SHARING)\n// ============================================================================\n\nmodel SquadMedia {\n  id String @id @default(cuid())\n\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  uploaderId String @map(\"uploader_id\")\n  uploader   User   @relation(fields: [uploaderId], references: [id], onDelete: Cascade)\n\n  // Title/caption\n  title String?\n\n  // Media details\n  kind       String @default(\"image\") // image, video\n  mimeType   String @map(\"mime_type\")\n  size       Int // bytes\n  storageKey String @map(\"storage_key\") // opaque key/path, not public URL\n\n  // Optional thumbnail\n  thumbStorageKey String? @map(\"thumb_storage_key\")\n  thumbMimeType   String? @map(\"thumb_mime_type\")\n  thumbSize       Int?    @map(\"thumb_size\")\n\n  // Visibility: private (uploader only), squad (default), public\n  visibility String @default(\"squad\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Soft delete\n  deletedAt DateTime? @map(\"deleted_at\")\n  deletedBy String?   @map(\"deleted_by\")\n\n  @@index([squadId])\n  @@index([uploaderId])\n  @@map(\"squad_media\")\n}\n\n// ============================================================================\n// SECURITY: SQUAD SECRETS (e.g., media encryption keys)\n// ============================================================================\n\nmodel SquadSecret {\n  id String @id @default(cuid())\n\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  kind   String // 'media_enc'\n  keyEnc String @map(\"key_enc\") // base64 of encrypted key material\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([squadId, kind])\n  @@map(\"squad_secrets\")\n}\n\n// ============================================================================\n// TRANSFER MARKET\n// ============================================================================\n\nmodel TransferOffer {\n  id String @id @default(cuid())\n\n  // From/To squads\n  fromSquadId String @map(\"from_squad_id\")\n  fromSquad   Squad  @relation(\"TransferFromSquad\", fields: [fromSquadId], references: [id])\n  toSquadId   String @map(\"to_squad_id\")\n  toSquad     Squad  @relation(\"TransferToSquad\", fields: [toSquadId], references: [id])\n\n  // Player (user ID)\n  playerId String @map(\"player_id\")\n\n  // Offer details\n  offerType    String @map(\"offer_type\") // permanent, loan\n  amount       Int\n  loanDuration Int?   @map(\"loan_duration\") // months, if loan\n\n  // Status\n  status          String  @default(\"pending\") // pending, accepted, rejected, cancelled\n  yellowSessionId String? @map(\"yellow_session_id\")\n\n  // Timestamps\n  expiresAt DateTime? @map(\"expires_at\")\n  createdAt DateTime  @default(now()) @map(\"created_at\")\n  updatedAt DateTime  @updatedAt @map(\"updated_at\")\n\n  @@map(\"transfer_offers\")\n}\n\n// ============================================================================\n// CHALLENGES & TERRITORY\n// ============================================================================\n\nmodel MatchChallenge {\n  id String @id @default(cuid())\n\n  fromSquadId String @map(\"from_squad_id\")\n  fromSquad   Squad  @relation(\"ChallengeFromSquad\", fields: [fromSquadId], references: [id])\n  toSquadId   String @map(\"to_squad_id\")\n  toSquad     Squad  @relation(\"ChallengeToSquad\", fields: [toSquadId], references: [id])\n\n  status String @default(\"pending\") // pending, accepted, rejected, cancelled\n\n  // Proposed details\n  proposedDate DateTime @map(\"proposed_date\")\n  pitchId      String?  @map(\"pitch_id\")\n  pitch        Pitch?   @relation(fields: [pitchId], references: [id])\n  message      String?\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"match_challenges\")\n}\n\nmodel Pitch {\n  id        String @id @default(cuid())\n  name      String\n  location  String\n  latitude  Float\n  longitude Float\n\n  // Territory Control\n  controllingSquadId String? @map(\"controlling_squad_id\")\n\n  // History\n  challenges MatchChallenge[]\n  matches    Match[]\n\n  // Squad scheduling\n  squadSchedules SquadSchedule[]\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"pitches\")\n}\n\n// ============================================================================\n// MATCHES (Core of MVP)\n// ============================================================================\n\nmodel Match {\n  id String @id @default(cuid())\n\n  // Teams\n  homeSquadId String @map(\"home_squad_id\")\n  homeSquad   Squad  @relation(\"MatchHomeSquad\", fields: [homeSquadId], references: [id])\n  awaySquadId String @map(\"away_squad_id\")\n  awaySquad   Squad  @relation(\"MatchAwaySquad\", fields: [awaySquadId], references: [id])\n\n  // Match Format (flexible: 5-a-side to 15-a-side, optional keeper)\n  playersPerSide Int     @default(11) @map(\"players_per_side\")\n  hasKeeper      Boolean @default(true) @map(\"has_keeper\")\n  matchFormat    String  @default(\"11v11\") @map(\"match_format\") // e.g. \"5v5\", \"7v7\", \"11v11\"\n\n  // Score\n  homeScore Int? @map(\"home_score\")\n  awayScore Int? @map(\"away_score\")\n\n  // Submitter\n  submittedBy String @map(\"submitted_by\")\n  submitter   User   @relation(\"MatchSubmitter\", fields: [submittedBy], references: [id])\n\n  // Membership context - which squad membership was active when submitted\n  // Enables historical attribution for multi-squad players\n  submittedByMembershipId String?      @map(\"submitted_by_membership_id\")\n  submittedByMembership   SquadMember? @relation(\"MatchSubmitterMembership\", fields: [submittedByMembershipId], references: [id])\n\n  // Status\n  status String @default(\"pending\") // pending, verified, disputed, finalized\n\n  // Public sharing\n  shareSlug String? @unique @map(\"share_slug\") // Short slug for public match URLs\n\n  // Timestamps\n  matchDate DateTime @map(\"match_date\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Oracle Verification (Chainlink)\n  latitude            Float?\n  longitude           Float?\n  weatherVerified     Boolean @default(false) @map(\"weather_verified\")\n  locationVerified    Boolean @default(false) @map(\"location_verified\")\n  verificationDetails Json?   @map(\"verification_details\")\n  agentInsights       Json?   @map(\"agent_insights\") // AI-generated captain reports\n\n  // Pitch Relation\n  pitchId String? @map(\"pitch_id\")\n  pitch   Pitch?  @relation(fields: [pitchId], references: [id])\n\n  // Session Relation (for ad-hoc \"Bibs vs Non-Bibs\" games)\n  sessionId String?  @map(\"session_id\")\n  session   Session? @relation(fields: [sessionId], references: [id])\n\n  // Blockchain\n  txId               String?   @map(\"tx_id\") // Algorand transaction ID\n  yellowFeeSessionId String?   @map(\"yellow_fee_session_id\")\n  yellowFeeSettledAt DateTime? @map(\"yellow_fee_settled_at\")\n\n  // Peer Rating Window\n  peerRatingsClosed  Boolean   @default(false) @map(\"peer_ratings_closed\")\n  peerRatingsCloseAt DateTime? @map(\"peer_ratings_close_at\")\n\n  // Relations\n  verifications MatchVerification[]\n  playerStats   PlayerMatchStats[]\n  xpGains       XPGain[]\n  peerRatings   PeerRating[]\n  motmVotes     MotmVote[]\n  rsvps         MatchRsvp[]\n\n  @@map(\"matches\")\n}\n\n// ============================================================================\n// PEER RATINGS & MOTM\n// ============================================================================\n\nmodel PeerRating {\n  id String @id @default(cuid())\n\n  matchId String @map(\"match_id\")\n  match   Match  @relation(fields: [matchId], references: [id])\n\n  raterId String        @map(\"rater_id\")\n  rater   PlayerProfile @relation(\"RatingGiven\", fields: [raterId], references: [id])\n\n  targetId String        @map(\"target_id\")\n  target   PlayerProfile @relation(\"RatingReceived\", fields: [targetId], references: [id])\n\n  attribute String // \"pace\", \"shooting\", \"passing\", \"dribbling\", \"defending\", \"physical\"\n  score     Int // 1-10\n  hypeTags  Json?   @map(\"hype_tags\") // [\"Clutch\", \"Engine\"]\n  weighted  Boolean @default(false)\n\n  // Consensus result (populated after window closes)\n  deviation Int? // How far this rating was from the median\n  scoutXP   Int? @map(\"scout_xp\") // XP earned/lost for this rating\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([matchId, raterId, targetId, attribute])\n  @@map(\"peer_ratings\")\n}\n\nmodel MotmVote {\n  id String @id @default(cuid())\n\n  matchId String @map(\"match_id\")\n  match   Match  @relation(fields: [matchId], references: [id])\n\n  voterId String        @map(\"voter_id\")\n  voter   PlayerProfile @relation(\"MotmVoteGiven\", fields: [voterId], references: [id])\n\n  targetId String        @map(\"target_id\")\n  target   PlayerProfile @relation(\"MotmVoteReceived\", fields: [targetId], references: [id])\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([matchId, voterId])\n  @@map(\"motm_votes\")\n}\n\nmodel MatchVerification {\n  id      String @id @default(cuid())\n  matchId String @map(\"match_id\")\n  match   Match  @relation(fields: [matchId], references: [id], onDelete: Cascade)\n\n  verifierId String @map(\"verifier_id\")\n  verifier   User   @relation(fields: [verifierId], references: [id])\n\n  // Verification details\n  verified  Boolean\n  homeScore Int?    @map(\"home_score\")\n  awayScore Int?    @map(\"away_score\")\n\n  // Trust\n  trustTier String @map(\"trust_tier\") // bronze, silver, gold, platinum\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([matchId, verifierId])\n  @@map(\"match_verifications\")\n}\n\n// ============================================================================\n// PLAYER MATCH STATS (For XP Calculation)\n// ============================================================================\n\nmodel PlayerMatchStats {\n  id String @id @default(cuid())\n\n  matchId String @map(\"match_id\")\n  match   Match  @relation(fields: [matchId], references: [id], onDelete: Cascade)\n\n  profileId String        @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  // Stats\n  goals         Int     @default(0)\n  assists       Int     @default(0)\n  cleanSheet    Boolean @default(false) @map(\"clean_sheet\")\n  rating        Float? // 1-10 match rating\n  minutesPlayed Int     @default(90) @map(\"minutes_played\")\n  hypeTags      Json?   @map(\"hype_tags\") // Aggregated consensus tags for the match\n\n  // Calculated XP\n  xpEarned Int @default(0) @map(\"xp_earned\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([matchId, profileId])\n  @@map(\"player_match_stats\")\n}\n\n// ============================================================================\n// XP GAINS (Audit Trail)\n// ============================================================================\n\nmodel XPGain {\n  id String @id @default(cuid())\n\n  matchId String? @map(\"match_id\")\n  match   Match?  @relation(fields: [matchId], references: [id])\n\n  profileId String @map(\"profile_id\")\n\n  // XP breakdown\n  baseXP  Int @map(\"base_xp\")\n  bonusXP Int @default(0) @map(\"bonus_xp\")\n  totalXP Int @map(\"total_xp\")\n\n  // Source\n  source      String // match, training, achievement, etc.\n  description String?\n\n  // Attribute distribution (JSON)\n  attributeBreakdown Json? @map(\"attribute_breakdown\")\n  // Example: {\"shooting\": 50, \"passing\": 30, \"physical\": 20}\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"xp_gains\")\n}\n\n// ============================================================================\n// ACHIEVEMENTS (Simplified for MVP)\n// ============================================================================\n\nmodel Achievement {\n  id String @id @default(cuid())\n\n  // Achievement type\n  type        String @unique // hat_trick, clean_sheet, etc.\n  title       String\n  description String\n\n  // Requirements\n  requirement Json // Flexible requirements\n\n  // Reward\n  xpReward Int @default(0) @map(\"xp_reward\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  unlockedBy PlayerAchievement[]\n\n  @@map(\"achievements\")\n}\n\nmodel PlayerAchievement {\n  id String @id @default(cuid())\n\n  profileId     String      @map(\"profile_id\")\n  achievementId String      @map(\"achievement_id\")\n  achievement   Achievement @relation(fields: [achievementId], references: [id])\n\n  unlockedAt DateTime @default(now()) @map(\"unlocked_at\")\n\n  @@unique([profileId, achievementId])\n  @@map(\"player_achievements\")\n}\n\n// ============================================================================\n// SESSIONS (Ad-hoc \"Weekly Games\")\n// ============================================================================\n\nmodel Session {\n  id      String @id @default(cuid())\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  name String // e.g. \"Wednesday Night Football\"\n  date DateTime @default(now())\n\n  // Attendance (pool of players available for this session)\n  attendees SessionAttendee[]\n\n  // Matches generated from this session (Bibs vs No Bibs)\n  matches Match[]\n\n  // Status: open (collecting players), balanced (teams picked), completed\n  status String @default(\"open\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"sessions\")\n}\n\nmodel SessionAttendee {\n  id        String  @id @default(cuid())\n  sessionId String  @map(\"session_id\")\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  profileId String        @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  // Preferred color/team for this session\n  teamPreference String? @map(\"team_preference\") // \"bibs\", \"no_bibs\"\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([sessionId, profileId])\n  @@map(\"session_attendees\")\n}\n\n// ============================================================================\n// AI AGENTS (KITE AI)\n// ============================================================================\n\nmodel AiAgent {\n  id           String   @id @default(cuid())\n  agentId      String   @unique @map(\"agent_id\")\n  passportId   String   @unique @map(\"passport_id\")\n  name         String\n  type         String // squad_manager, scout, fitness, social, twin_player, twin_squad, coach_external\n  description  String\n  reputation   Int      @default(100)\n  capabilities String[]\n\n  // Kite Passport ownership / scope\n  ownerType     String? @map(\"owner_type\") // 'player' | 'squad' | 'platform' | 'external'\n  ownerId       String? @map(\"owner_id\")\n  walletAddress String? @map(\"wallet_address\") // Kite chain address controlled by this agent\n\n  // Service-provider mode (this agent sells an x402 service to other agents)\n  serviceUrl    String? @map(\"service_url\")\n  servicePrice  String? @map(\"service_price\") // e.g. \"0.10\"\n  serviceAsset  String? @default(\"USDC\") @map(\"service_asset\")\n  serviceActive Boolean @default(false) @map(\"service_active\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  sessions      KiteSession[]\n  attestations  Attestation[]    @relation(\"AttestationSigner\")\n  coachingGiven CoachingEffect[] @relation(\"CoachingEffectCoach\")\n  playerTwin    PlayerTwin?\n\n  @@index([ownerType, ownerId])\n  @@map(\"ai_agents\")\n}\n\n// ============================================================================\n// KITE PASSPORT SPENDING SESSIONS\n// Mirrors `kpass agent:session` — every paid call by an agent runs inside a\n// session bounded by per-tx + total budget + ttl + scope. Persisted for audit.\n// ============================================================================\n\nmodel KiteSession {\n  id      String  @id @default(cuid())\n  agentId String  @map(\"agent_id\")\n  agent   AiAgent @relation(fields: [agentId], references: [id], onDelete: Cascade)\n\n  taskSummary     String @map(\"task_summary\")\n  scope           Json? // free-form scope hints (service categories, allowlisted urls)\n  asset           String @default(\"USDC\")\n  paymentApproach String @default(\"x402_http\") @map(\"payment_approach\")\n\n  maxPerTx Float @map(\"max_per_tx\")\n  maxTotal Float @map(\"max_total\")\n  spent    Float @default(0)\n  txCount  Int   @default(0) @map(\"tx_count\")\n\n  status     String  @default(\"pending\") // pending | active | expired | exhausted | revoked\n  approvedBy String? @map(\"approved_by\") // user id (passkey approval)\n  requestId  String? @unique @map(\"request_id\") // kpass session request id when human-approved\n\n  expiresAt DateTime @map(\"expires_at\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  attestations Attestation[]\n\n  @@index([agentId, status])\n  @@map(\"kite_sessions\")\n}\n\n// ============================================================================\n// ATTESTATIONS\n// Every twin stat change requires a signed attestation. Records the on-chain\n// settlement tx hash on Kite when the originating action was a paid x402 call.\n// ============================================================================\n\nmodel Attestation {\n  id String @id @default(cuid())\n\n  subjectType String @map(\"subject_type\") // 'player' | 'squad' | 'match' | 'agent'\n  subjectId   String @map(\"subject_id\")\n\n  kind    String // 'match_result' | 'peer_rating' | 'activity_sync' | 'coaching_effect' | 'motm' | 'rsvp_compliance'\n  payload Json // canonicalized data that was signed\n\n  signerAgentId String?  @map(\"signer_agent_id\")\n  signerAgent   AiAgent? @relation(\"AttestationSigner\", fields: [signerAgentId], references: [id])\n  signature     String? // hex EIP-712 / personal_sign\n\n  // Kite-chain settlement\n  network     String  @default(\"kite-testnet\")\n  txHash      String? @map(\"tx_hash\")\n  facilitator String? // pieverse address used\n  amountUsdc  Float?  @map(\"amount_usdc\") // amount paid for this attestation, if any\n\n  // Optional link back to the spending session that paid for this attestation\n  sessionId String?      @map(\"session_id\")\n  session   KiteSession? @relation(fields: [sessionId], references: [id])\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@index([subjectType, subjectId, kind])\n  @@index([txHash])\n  @@map(\"attestations\")\n}\n\n// ============================================================================\n// COACHING EFFECTS\n// Time-decaying buffs purchased via x402 from a coach agent. Stat = base +\n// sum(active CoachingEffect modifiers). Every effect points back to the\n// attestation that paid for + signed it.\n// ============================================================================\n\nmodel CoachingEffect {\n  id String @id @default(cuid())\n\n  // who is being coached\n  targetType String @map(\"target_type\") // 'player' | 'squad'\n  targetId   String @map(\"target_id\")\n\n  // who provided the coaching\n  coachAgentId String  @map(\"coach_agent_id\")\n  coachAgent   AiAgent @relation(\"CoachingEffectCoach\", fields: [coachAgentId], references: [id])\n\n  // what the buff is\n  attribute String // e.g. 'shooting' | 'attack' | 'sharpness' | 'teamwork'\n  modifier  Float // additive, can be negative (e.g. fatigue from over-training)\n  reason    String?\n\n  // proof\n  attestationId String? @map(\"attestation_id\")\n  amountUsdc    Float?  @map(\"amount_usdc\")\n\n  // lifetime\n  startsAt  DateTime @default(now()) @map(\"starts_at\")\n  expiresAt DateTime @map(\"expires_at\")\n  active    Boolean  @default(true)\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@index([targetType, targetId, active, expiresAt])\n  @@map(\"coaching_effects\")\n}\n\nmodel AiMemory {\n  id     String @id @default(cuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Stored JSON representation of NarrativeEntry[]\n  history Json @default(\"[]\")\n\n  // Array of strings or JSON for key insights\n  keyInsights Json @default(\"[]\") @map(\"key_insights\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@unique([userId])\n  @@map(\"ai_memories\")\n}\n\n// ============================================================================\n// PREDICTION MARKETS\n// ============================================================================\n\nmodel PredictionMarket {\n  id          String  @id @default(cuid())\n  question    String // \"Who will win the match?\"\n  description String? // Additional context\n  category    String // 'sports', 'politics', 'entertainment', 'crypto'\n  sportType   String? // 'football', 'basketball', 'tennis', etc.\n\n  // Market metadata\n  creatorId   String  @map(\"creator_id\")\n  creatorName String? @map(\"creator_name\") // Telegram username\n\n  // Timing\n  deadline DateTime // When betting closes\n  settleBy DateTime @map(\"settle_by\") // When AI must resolve\n\n  // Status\n  status String  @default(\"active\") // 'active', 'settled', 'cancelled', 'disputed'\n  result String? // The winning option ID\n\n  // Payout tracking\n  totalPool  Int @default(0) @map(\"total_pool\") // Total TON staked\n  creatorFee Int @default(0) @map(\"creator_fee\") // Creator's share\n\n  // AI verification\n  aiVerified  Boolean @default(false) @map(\"ai_verified\")\n  aiReasoning String? @map(\"ai_reasoning\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  options PredictionOption[]\n  bets    PredictionBet[]\n\n  @@map(\"prediction_markets\")\n}\n\nmodel PredictionOption {\n  id       String           @id @default(cuid())\n  marketId String           @map(\"market_id\")\n  market   PredictionMarket @relation(fields: [marketId], references: [id], onDelete: Cascade)\n\n  text     String // \"Team A wins\", \"Draw\", \"Team B wins\"\n  odds     Float  @default(2.0) // Payout multiplier\n  totalBet Int    @default(0) @map(\"total_bet\") // Total staked on this option\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  bets PredictionBet[]\n\n  @@unique([marketId, text])\n  @@map(\"prediction_options\")\n}\n\nmodel PredictionBet {\n  id       String           @id @default(cuid())\n  marketId String           @map(\"market_id\")\n  market   PredictionMarket @relation(fields: [marketId], references: [id], onDelete: Cascade)\n\n  optionId String           @map(\"option_id\")\n  option   PredictionOption @relation(fields: [optionId], references: [id], onDelete: Cascade)\n\n  userId   String  @map(\"user_id\")\n  userName String? @map(\"user_name\") // Telegram username\n\n  amount       Int // Amount in nanoTON\n  potentialWin Int @map(\"potential_win\") // If they win\n\n  // Status\n  status String @default(\"pending\") // 'pending', 'won', 'lost', 'refunded'\n\n  // Telegram message for dispute\n  messageId String? @map(\"message_id\")\n\n  // Timestamps\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"prediction_bets\")\n}\n\n// ============================================================================\n// AVAILABILITY & SCHEDULING (Multi-Squad Support)\n// ============================================================================\n\n// Recurring weekly availability - \"I play every Tuesday\"\nmodel SquadAvailability {\n  id     String @id @default(cuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  squadId String @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  // Day of week (ISO: 1=Monday, 7=Sunday)\n  dayOfWeek Int @map(\"day_of_week\") // 1-7\n\n  // Time preference\n  timeSlot String? // \"morning\", \"afternoon\", \"evening\", \"any\"\n\n  // Availability status\n  isAvailable Boolean @default(true) @map(\"is_available\")\n\n  // Notes (e.g., \"only if home game\", \"after 6pm\")\n  notes String?\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@unique([userId, squadId, dayOfWeek])\n  @@map(\"squad_availabilities\")\n}\n\n// One-off match RSVP - \"I'm playing this Saturday\"\nmodel MatchRsvp {\n  id     String @id @default(cuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  matchId String @map(\"match_id\")\n  match   Match  @relation(fields: [matchId], references: [id], onDelete: Cascade)\n\n  // Response status\n  status String @default(\"pending\") // \"available\", \"unavailable\", \"maybe\"\n\n  // Payment tracking for informal games (subs/pitch fees)\n  isPaid      Boolean   @default(false) @map(\"is_paid\")\n  paidAt      DateTime? @map(\"paid_at\")\n  amountPaid  Int?      @map(\"amount_paid\") // in minor units (e.g. pence, or nanoTON)\n  paymentType String?   @map(\"payment_type\") // 'cash', 'transfer', 'crypto'\n\n  // Position preference for this match\n  position String? // GK, DF, MF, ST, WG, any\n\n  // Notes (e.g., \"might be late\", \"bringing a friend\")\n  notes String?\n\n  respondedAt DateTime? @map(\"responded_at\")\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n\n  @@unique([userId, matchId])\n  @@map(\"match_rsvps\")\n}\n\n// Squad's default schedule - \"We play every Saturday 2pm at XYZ\"\nmodel SquadSchedule {\n  id      String @id @default(cuid())\n  squadId String @unique @map(\"squad_id\")\n  squad   Squad  @relation(fields: [squadId], references: [id], onDelete: Cascade)\n\n  // Day of week (ISO: 1=Monday, 7=Sunday)\n  dayOfWeek Int @map(\"day_of_week\") // 1-7\n\n  // Default time\n  time String? // \"14:00\", \"2pm\"\n\n  // Default location\n  locationId String? @map(\"location_id\")\n  location   Pitch?  @relation(fields: [locationId], references: [id])\n\n  // Recurrence\n  isRecurring Boolean @default(true) @map(\"is_recurring\")\n\n  // Active/inactive\n  isActive Boolean @default(true) @map(\"is_active\")\n\n  // Notes\n  notes String?\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"squad_schedules\")\n}\n\n// ============================================================================\n// PLAYER TWINS — Kite Passport-backed autonomous agents per player\n// Every player gets a twin whose stats are a verifiable function of IRL\n// attestations (match results, peer ratings, activity sync). Twins can hire\n// coaches (paid via x402), compete in simulated tournaments, and trade\n// scouting data with other twins.\n// ============================================================================\n\nmodel PlayerTwin {\n  id        String        @id @default(cuid())\n  profileId String        @unique @map(\"profile_id\")\n  profile   PlayerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n\n  // Kite Passport identity\n  agentId String  @unique @map(\"agent_id\") // AiAgent.id\n  agent   AiAgent @relation(fields: [agentId], references: [id], onDelete: Cascade)\n\n  // Twin state\n  level    Int @default(1)\n  xp       Int @default(0)\n  prestige Int @default(0) // earned through wins, coaching, attestations\n\n  // Autonomous config (what the twin is allowed to do within its session budget)\n  autoHireCoaches  Boolean @default(false) @map(\"auto_hire_coaches\")\n  autoCompete      Boolean @default(false) @map(\"auto_compete\")\n  weeklyBudgetUsdc Float   @default(5.0) @map(\"weekly_budget_usdc\")\n\n  // Stats snapshot (denormalized from attestations for fast reads)\n  baseAttributes    Json      @default(\"{}\") @map(\"base_attributes\") // { pace: 50, shooting: 50, ... }\n  activeModifiers   Json      @default(\"[]\") @map(\"active_modifiers\") // CoachingEffect[] with expiry\n  lastAttestationAt DateTime? @map(\"last_attestation_at\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  simulations TwinSimulationParticipant[]\n\n  @@map(\"player_twins\")\n}\n\n// ============================================================================\n// TWIN SIMULATIONS — overnight tournaments between player twins\n// ============================================================================\n\nmodel TwinSimulation {\n  id     String @id @default(cuid())\n  name   String // \"Week 14 Round-Robin\"\n  format String @default(\"round_robin\") // round_robin | knockout | league\n  status String @default(\"pending\") // pending | running | completed | settled\n\n  // Prize pool funded by entry fees (x402 settled)\n  entryFeeUsdc    Float   @default(0)\n  totalPrizeUsdc  Float   @default(0)\n  prizePoolTxHash String? @map(\"prize_pool_tx_hash\")\n\n  // Kite-chain settlement\n  network       String  @default(\"kite-testnet\")\n  attestationId String? @map(\"attestation_id\") // master attestation for the whole simulation\n\n  startedAt   DateTime?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n\n  participants TwinSimulationParticipant[]\n  matches      TwinSimulationMatch[]\n\n  @@map(\"twin_simulations\")\n}\n\nmodel TwinSimulationParticipant {\n  id           String         @id @default(cuid())\n  simulationId String         @map(\"simulation_id\")\n  simulation   TwinSimulation @relation(fields: [simulationId], references: [id], onDelete: Cascade)\n  twinId       String         @map(\"twin_id\")\n  twin         PlayerTwin     @relation(fields: [twinId], references: [id], onDelete: Cascade)\n\n  // Tournament standing\n  wins         Int   @default(0)\n  draws        Int   @default(0)\n  losses       Int   @default(0)\n  goalsFor     Int   @default(0) @map(\"goals_for\")\n  goalsAgainst Int   @default(0) @map(\"goals_against\")\n  points       Int   @default(0)\n  prizeUsdc    Float @default(0) @map(\"prize_usdc\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([simulationId, twinId])\n  @@map(\"twin_simulation_participants\")\n}\n\nmodel TwinSimulationMatch {\n  id           String         @id @default(cuid())\n  simulationId String         @map(\"simulation_id\")\n  simulation   TwinSimulation @relation(fields: [simulationId], references: [id], onDelete: Cascade)\n\n  homeTwinId String @map(\"home_twin_id\")\n  awayTwinId String @map(\"away_twin_id\")\n  homeScore  Int?\n  awayScore  Int?\n  round      Int    @default(1)\n\n  // Each simulated match produces an attestation\n  attestationId String? @map(\"attestation_id\")\n\n  playedAt  DateTime?\n  createdAt DateTime  @default(now()) @map(\"created_at\")\n\n  @@map(\"twin_simulation_matches\")\n}\n\n// ============================================================================\n// GROWTH: WAITLIST SIGNUPS\n// ============================================================================\n\nmodel WaitlistSignup {\n  id        String   @id @default(cuid())\n  email     String\n  source    String?\n  context   Json?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([email])\n  @@map(\"waitlist_signups\")\n}\n"
}

